index 04ea12ef0f12..b03ebd84c0d5 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -1010,6 +1010,10 @@ bool VectorCombine::scalarizeBinopOrCmp(Instruction &I) {
   if (IsConst1)
     V1 = ConstantExpr::getExtractElement(VecC1, Builder.getInt64(Index));

+  // Check for poison or zero in the divisor for sdiv to avoid UB.
+  if (Opcode == Instruction::SDiv && (!V1 || match(V1, m_Zero()))) {
+    return false; // Abort transformation if divisor is poison or zero.
